document.addEventListener('DOMContentLoaded',function(){AOS.init({duration:800,easing:'ease',once:true,offset:100});const menuToggle = document.querySelector('.menu-toggle');const navList = document.querySelector('.nav-list');if(menuToggle){menuToggle.addEventListener('click',function(){navList.classList.toggle('active');menuToggle.classList.toggle('active');});}const navLinks = document.querySelectorAll('.nav-link');navLinks.forEach(link =>{link.addEventListener('click',function(){navList.classList.remove('active');menuToggle.classList.remove('active');});});document.querySelectorAll('a[href^="#"]').forEach(anchor =>{anchor.addEventListener('click',function(e){e.preventDefault();const targetId = this.getAttribute('href');if(targetId === '#')return;const targetElement = document.querySelector(targetId);if(targetElement){const headerHeight = document.querySelector('.header').offsetHeight;const targetPosition = targetElement.getBoundingClientRect().top + window.pageYOffset - headerHeight;window.scrollTo({top:targetPosition,behavior:'smooth'});}});});const filterButtons = document.querySelectorAll('.filter-btn');const galleryItems = document.querySelectorAll('.gallery-item');filterButtons.forEach(button =>{button.addEventListener('click',function(){filterButtons.forEach(btn => btn.classList.remove('active'));this.classList.add('active');const filterValue = this.getAttribute('data-filter');galleryItems.forEach(item =>{if(filterValue === 'all' || item.getAttribute('data-category')=== filterValue){item.style.display = 'block';setTimeout(()=>{item.style.opacity = '1';item.style.transform = 'scale(1)';},100);}else{item.style.opacity = '0';item.style.transform = 'scale(0.8)';setTimeout(()=>{item.style.display = 'none';},300);}});});});const galleryZoomLinks = document.querySelectorAll('.gallery-zoom');const modal = document.querySelector('.gallery-modal');const modalImg = document.getElementById('modal-img');const modalCaption = document.querySelector('.modal-caption');const closeModal = document.querySelector('.close-modal');const modalPrev = document.querySelector('.modal-prev');const modalNext = document.querySelector('.modal-next');let currentImageIndex = 0;const galleryImages =[];galleryZoomLinks.forEach((link,index)=>{const imgSrc = link.getAttribute('href');const imgCaption = link.parentElement.querySelector('h3').textContent;galleryImages.push({src:imgSrc,caption:imgCaption});link.addEventListener('click',function(e){e.preventDefault();openModal(index);});});function openModal(index){modal.style.display = 'block';currentImageIndex = index;updateModalImage();}function updateModalImage(){modalImg.src = galleryImages[currentImageIndex].src;modalCaption.textContent = galleryImages[currentImageIndex].caption;}if(closeModal){closeModal.addEventListener('click',function(){modal.style.display = 'none';});}if(modalPrev){modalPrev.addEventListener('click',function(){currentImageIndex =(currentImageIndex - 1 + galleryImages.length)% galleryImages.length;updateModalImage();});}if(modalNext){modalNext.addEventListener('click',function(){currentImageIndex =(currentImageIndex + 1)% galleryImages.length;updateModalImage();});}window.addEventListener('click',function(e){if(e.target === modal){modal.style.display = 'none';}});const depoimentosSlider = document.querySelector('.depoimentos-slider');const depoimentos = document.querySelectorAll('.depoimento');const prevBtn = document.querySelector('.prev-btn');const nextBtn = document.querySelector('.next-btn');let depoimentoIndex = 0;function showDepoimento(index){if(!depoimentosSlider)return;depoimentos.forEach(depoimento =>{depoimento.style.display = 'none';});depoimentos[index].style.display = 'block';}if(depoimentos.length > 0){showDepoimento(depoimentoIndex);}if(prevBtn){prevBtn.addEventListener('click',function(){depoimentoIndex =(depoimentoIndex - 1 + depoimentos.length)% depoimentos.length;showDepoimento(depoimentoIndex);});}if(nextBtn){nextBtn.addEventListener('click',function(){depoimentoIndex =(depoimentoIndex + 1)% depoimentos.length;showDepoimento(depoimentoIndex);});}const contactForm = document.getElementById('contact-form');if(contactForm){contactForm.addEventListener('submit',function(e){e.preventDefault();let isValid = true;const requiredFields = contactForm.querySelectorAll('[required]');requiredFields.forEach(field =>{if(!field.value.trim()){isValid = false;field.classList.add('error');}else{field.classList.remove('error');}});const emailField = contactForm.querySelector('input[type="email"]');if(emailField && emailField.value){const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;if(!emailPattern.test(emailField.value)){isValid = false;emailField.classList.add('error');}}if(isValid){alert('Mensagem enviada com sucesso! Entraremos em contato em breve.');contactForm.reset();}else{alert('Por favor,preencha todos os campos obrigatórios corretamente.');}});}const header = document.querySelector('.header');let lastScrollTop = 0;window.addEventListener('scroll',function(){let scrollTop = window.pageYOffset || document.documentElement.scrollTop;if(scrollTop > lastScrollTop){header.style.transform = 'translateY(-100%)';}else{header.style.transform = 'translateY(0)';}if(scrollTop === 0){header.classList.remove('scrolled');}else{header.classList.add('scrolled');}lastScrollTop = scrollTop <= 0 ? 0:scrollTop;});const newsletterForm = document.querySelector('.newsletter-form');if(newsletterForm){newsletterForm.addEventListener('submit',function(e){e.preventDefault();const emailInput = this.querySelector('input[type="email"]');if(emailInput && emailInput.value){alert('Obrigado por se inscrever em nossa newsletter!');emailInput.value = '';}else{alert('Por favor,insira um e-mail válido.');}});}});